function Poll() {
  useEffect(() => {
    let timerId: ReturnType<typeof setTimeout>;
    let cancelled = false;
    function tick() {
      fetch('/api/status').then(r => r.json()).then(data => {
        if (cancelled) return;
        setStatus(data);
        timerId = setTimeout(tick, 5000);
      });
    }
    tick();
    return () => {
      cancelled = true;
      clearTimeout(timerId);
    };
  }, []);
}

