async function fetchWithTimeout(url: string, ms: number) {
  const ac = new AbortController();
  const id = setTimeout(() => ac.abort(), ms);
  try {
    const r = await fetch(url, { signal: ac.signal });
    return r;
  } finally {
    clearTimeout(id);
  }
}
// Or AbortSignal.timeout (newer):
